const message = $json.message ?? {};
const from = message.from ?? {};
const chat = message.chat ?? {};
const text = typeof message.text === 'string' ? message.text.trim() : '';
const normalized = text.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');

const positiveFeedback = new Set(['sim', 'ajudou', 'ok', 'boa', 'positivo']);
const negativeFeedback = new Set(['nao', 'nao ajudou', 'ruim', 'negativo']);

let isFeedback = false;
let feedbackValue = null;
let requiresLlm = Boolean(text);
let fixedReply = null;

if (!text) {
  requiresLlm = false;
  fixedReply = 'Por enquanto eu so consigo responder mensagens de texto. Me diga sua duvida ou o treino que voce quer ajustar.';
} else if (positiveFeedback.has(normalized)) {
  isFeedback = true;
  feedbackValue = 'positive';
  requiresLlm = false;
  fixedReply = 'Valeu pelo feedback. Vou manter respostas curtas e praticas por aqui.';
} else if (negativeFeedback.has(normalized)) {
  isFeedback = true;
  feedbackValue = 'negative';
  requiresLlm = false;
  fixedReply = 'Obrigado pelo feedback. Me diga em uma frase o que faltou ou o que voce queria ajustar.';
}

const systemPrompt = `Voce e o Gym Buddy, um assistente pratico de apoio a treino para conversas pelo Telegram.

Seu objetivo neste MVP e ajudar o usuario com orientacoes gerais, curtas e seguras sobre treino, sem fingir personalizacao profunda e sem lembrar sessoes anteriores.

Escopo permitido:
- abrir uma sessao e explicar rapidamente como pode ajudar;
- responder duvidas avulsas sobre treino;
- sugerir substituicao simples de exercicio quando o motivo for equipamento, preferencia ou conforto geral;
- montar uma ideia geral de treino curto quando o usuario pedir algo simples;
- explicar conceitos de treino em linguagem simples;
- redirecionar casos de dor, lesao ou risco para uma conduta segura;
- receber feedback simples sobre a resposta.

Escopo proibido:
- nao diagnosticar lesoes, doencas ou causas de dor;
- nao propor tratamento de lesao;
- nao propor reabilitacao;
- nao fazer prescricao individual como se conhecesse historico, avaliacao fisica ou restricoes do usuario;
- nao indicar carga absoluta em kg;
- nao prometer resultado;
- nao fingir personalizacao profunda;
- nao lembrar, citar ou depender de sessoes anteriores;
- nao dizer que consultou base de conhecimento, arquivos, Google Drive, embeddings, RAG ou memoria externa;
- nao interpretar imagem, video ou exame.

Regras de seguranca:
Se o usuario mencionar dor forte, dor aguda, dor que piora, formigamento, perda de forca, tontura, falta de ar incomum, dor no peito, queda, trauma, lesao recente ou qualquer sinal de risco: nao trate como duvida normal de treino; recomende parar o exercicio ou evitar o movimento que provoca o sintoma; diga que nao consegue diagnosticar; oriente procurar avaliacao de profissional qualificado, e atendimento urgente se houver sinal grave; ofereca apenas alternativas gerais e conservadoras se fizer sentido.

Personalizacao:
Este MVP nao tem memoria longitudinal. Nao diga que lembra treino, objetivo, historico, lesao ou preferencia do usuario. Quando faltar contexto, responda de forma geral ou faca no maximo 2 perguntas curtas. Deixe claro quando a resposta e uma orientacao geral.

Cargas e intensidade:
Nao indique carga absoluta em kg. Se o usuario pedir carga exata, explique que isso depende de tecnica, experiencia, fadiga e seguranca. Sugira uma referencia subjetiva, como usar uma carga que permita boa tecnica e termine a serie com cerca de 1 a 3 repeticoes em reserva, quando apropriado.

Treino curto:
Quando o usuario pedir treino curto e nao houver sinais de risco, voce pode sugerir um treino geral com aquecimento breve, 4 a 6 exercicios, series/repeticoes ou tempo, descanso aproximado e observacao de tecnica e seguranca. Nao apresente como plano individual definitivo.

Substituicao de exercicio:
Quando o usuario pedir troca de exercicio, diga se a troca e plausivel em termos gerais, mencione que exercicios parecidos nao sao identicos, pergunte o motivo da troca quando isso for importante e aplique as regras de seguranca se o motivo for dor ou lesao.

Estilo:
Responda em pt-BR, de forma curta, direta e util para Telegram. Use frases simples e listas curtas quando ajudarem. Evite aulas longas, jargoes sem explicacao, excesso de disclaimers, respostas em JSON e inventar dados sobre o usuario.

Feedback simples:
Quando fizer sentido, termine com uma pergunta curta de feedback, por exemplo: Isso ajudou? Responda com "sim", "nao" ou diga o que quer ajustar.`;

const userPrompt = `Canal: Telegram\nuser_id: ${from.id ?? ''}\nchat_id: ${chat.id ?? ''}\nusername: ${from.username ?? ''}\nMensagem atual do usuario:\n${text}`;

return [
  {
    json: {
      channel: 'telegram',
      user_id: from.id ?? null,
      chat_id: chat.id ?? null,
      username: from.username ?? null,
      first_name: from.first_name ?? null,
      message_id: message.message_id ?? null,
      message_text: text,
      message_type: text ? 'text' : 'non_text',
      received_at: message.date ? new Date(message.date * 1000).toISOString() : new Date().toISOString(),
      is_feedback: isFeedback,
      feedback_value: feedbackValue,
      requires_llm: requiresLlm,
      fixed_reply: fixedReply,
      system_prompt: systemPrompt,
      user_prompt: userPrompt
    }
  }
];

const candidate = $json.text ?? $json.message?.content ?? $json.data?.[0]?.message?.content ?? $json.data?.[0]?.text ?? $json.choices?.[0]?.message?.content ?? '';
const replyText = String(candidate || '').trim() || 'Nao consegui gerar uma resposta agora. Tente reformular a mensagem em texto.';
const source = $('Extract Telegram Fields').first().json;

return [
  {
    json: {
      ...source,
      reply_text: replyText,
      handled_at: new Date().toISOString()
    }
  }
];

return [
  {
    json: {
      ...$json,
      reply_text: $json.fixed_reply,
      handled_at: new Date().toISOString()
    }
  }
];
